for (const item of items) {
  const lead = item.json;
  const url = lead.website || '';
  if (!lead.hasWebsite || !url || url.includes('google.com/maps') || url.includes('instagram.com')) {
    noWebsiteLeads.push({...lead, tagsTech:[], gapsDetected:['sem_site','sem_analytics','sem_pixel','sem_google_ads','sem_blog','sem_seo','sem_schema','sem_whatsapp_widget','sem_agendamento'], fazTrafegoPago:false, temAgendamento:false, websiteScanned:false, instagramUrl:'', instagramSeguidores:0});
  } else {
    urlsToScan.push({ url: url, userData: { leadIndex: urlsToScan.length, nome: lead.nome } });
  }
}
return [{ json: { urlsToScan, noWebsiteLeads, allLeads: items.map(i => i.json), hasUrlsToScan: urlsToScan.length > 0 } }];

const scanResults = $input.all().map(i => i.json);
const prepData = $('Prepare Website URLs').first().json;
const allLeads = prepData.allLeads;
const noWebsiteLeads = prepData.noWebsiteLeads;
const results = [];

for (const lead of allLeads) {
  const url = lead.website || '';
  const existing = noWebsiteLeads.find(n => n.gmapsUrl === lead.gmapsUrl);
  if (existing) { results.push({ json: existing }); continue; }

  const scanResult = scanResults.find(s => {
    if (s.userData && s.userData.leadIndex !== undefined) {
      const idx = s.userData.leadIndex;
      const urlsToScan = prepData.urlsToScan || [];
      return urlsToScan[idx] && urlsToScan[idx].url === url;
    }
    let hostname = '';
    try { hostname = new URL(url).hostname.replace('www.', ''); } catch(e) {}
    let scanHost = '';
    try { scanHost = new URL(s.url || '').hostname.replace('www.', ''); } catch(e) {}
    return hostname && scanHost && (hostname === scanHost || s.url?.includes(hostname));
  });

  const html = (scanResult?.html || '').toLowerCase();

  if (!html || html.length < 100) {
    results.push({ json: { ...lead, tagsTech:[], gapsDetected:['website_error'], fazTrafegoPago:false, temAgendamento:false, websiteScanned:false, instagramUrl:'', instagramSeguidores:0 }});
    continue;
  }

  const tags = [];
  const gaps = [];

  if (url.startsWith('https')) tags.push('tem_ssl'); else gaps.push('sem_ssl');
  if (html.includes('gtag') || html.includes('google-analytics') || html.includes('googletagmanager.com/gtag') || html.includes('googletagmanager')) tags.push('tem_ga4'); else gaps.push('sem_analytics');
  if (html.includes('gtm-') || html.includes('googletagmanager.com/ns.html')) tags.push('tem_gtm');
  if (html.includes('fbq(') || html.includes('facebook.com/tr') || html.includes('fbevents') || html.includes('connect.facebook.net')) tags.push('tem_pixel'); else gaps.push('sem_pixel');
  if (html.includes('googleadservices') || html.includes('google_conversion') || html.includes('ads/ga-audiences') || html.includes('googlesyndication') || html.includes('aw-')) tags.push('tem_google_ads'); else gaps.push('sem_google_ads');
  if (html.includes('analytics.tiktok.com')) tags.push('tem_tiktok_pixel');
  if (html.includes('/blog') || html.includes('/artigos') || html.includes('/noticias') || html.includes('/news')) tags.push('tem_blog'); else gaps.push('sem_blog');
  if (html.includes('meta name="description"') || html.includes("meta name='description'") || html.includes('meta property="og:description"')) {} else gaps.push('sem_seo');
  if (html.includes('application/ld+json') || html.includes('schema.org')) tags.push('tem_schema'); else gaps.push('sem_schema');
  if (html.includes('wp-content') || html.includes('wp-includes') || html.includes('wordpress')) tags.push('tem_wordpress');
  else if (html.includes('wixstatic') || html.includes('wix.com') || html.includes('_wix_browser_sess')) tags.push('tem_wix');
  if (html.includes('wa.me/') || html.includes('api.whatsapp.com') || html.includes('whatsapp')) tags.push('tem_whatsapp_widget'); else gaps.push('sem_whatsapp_widget');
  if (html.includes('tawk.to') || html.includes('tidio') || html.includes('zendesk') || html.includes('crisp.chat') || html.includes('jivochat') || html.includes('livechat')) tags.push('tem_chat_widget');
  if (html.includes('doctoralia') || html.includes('booksy') || html.includes('calendly') || html.includes('agendamento') || html.includes('agendar') || html.includes('marcar consulta') || html.includes('hotdoc') || html.includes('clinicorp')) tags.push('tem_agendamento'); else gaps.push('sem_agendamento');
  if (html.includes('<form') || html.includes('wpcf7') || html.includes('contact-form') || html.includes('elementor-form')) tags.push('tem_formulario');

  let instagramUrl = '';
  const igPatterns = [
    /href=["']https?:\/\/(?:www\.)?instagram\.com\/([a-z0-9_\.]{2,30})\/?["']/gi,
    /instagram\.com\/([a-z0-9_\.]{2,30})\/?/gi
  ];
  const igExclude = ['p','reel','explore','accounts','about','legal','developer','privacy','reels','stories'];
  for (const pattern of igPatterns) {
    let match;
    while ((match = pattern.exec(html)) !== null) {
      if (match[1] && !igExclude.includes(match[1].toLowerCase())) {
        instagramUrl = 'https://instagram.com/' + match[1];
        break;
      }
    }
    if (instagramUrl) break;
  }
  if (!instagramUrl) gaps.push('sem_instagram');

  results.push({ json: {
    ...lead,
    tagsTech: tags,
    gapsDetected: gaps,
    fazTrafegoPago: tags.includes('tem_pixel') || tags.includes('tem_google_ads'),
    temAgendamento: tags.includes('tem_agendamento'),
    websiteScanned: true,
    instagramUrl: instagramUrl,
    instagramSeguidores: 0
  }});
}
return results;

