  if (html.includes('googleadservices') || html.includes('google_conversion') || html.includes('ads/ga-audiences') || html.includes('googlesyndication') || html.includes('aw-')) tags.push('tem_google_ads'); else gaps.push('sem_google_ads');
  if (html.includes('analytics.tiktok.com')) tags.push('tem_tiktok_pixel');
  if (html.includes('/blog') || html.includes('/artigos') || html.includes('/noticias') || html.includes('/news')) tags.push('tem_blog'); else gaps.push('sem_blog');
  if (html.includes('meta name="description"') || html.includes("meta name='description'") || html.includes('meta property="og:description"')) {} else gaps.push('sem_seo');
  if (html.includes('application/ld+json') || html.includes('schema.org')) tags.push('tem_schema'); else gaps.push('sem_schema');
  if (html.includes('wp-content') || html.includes('wp-includes') || html.includes('wordpress')) tags.push('tem_wordpress');
  else if (html.includes('wixstatic') || html.includes('wix.com') || html.includes('_wix_browser_sess')) tags.push('tem_wix');
  if (html.includes('wa.me/') || html.includes('api.whatsapp.com') || html.includes('whatsapp')) tags.push('tem_whatsapp_widget'); else gaps.push('sem_whatsapp_widget');
  if (html.includes('tawk.to') || html.includes('tidio') || html.includes('zendesk') || html.includes('crisp.chat') || html.includes('jivochat') || html.includes('livechat')) tags.push('tem_chat_widget');
  if (html.includes('doctoralia') || html.includes('booksy') || html.includes('calendly') || html.includes('agendamento') || html.includes('agendar') || html.includes('marcar consulta') || html.includes('hotdoc') || html.includes('clinicorp')) tags.push('tem_agendamento'); else gaps.push('sem_agendamento');
  if (html.includes('<form') || html.includes('wpcf7') || html.includes('contact-form') || html.includes('elementor-form')) tags.push('tem_formulario');

  let instagramUrl = '';
  const igPatterns = [
    /href=["']https?:\/\/(?:www\.)?instagram\.com\/([a-z0-9_\.]{2,30})\/?["']/gi,
    /instagram\.com\/([a-z0-9_\.]{2,30})\/?/gi
  ];
  const igExclude = ['p','reel','explore','accounts','about','legal','developer','privacy','reels','stories'];
  for (const pattern of igPatterns) {
    let match;
    while ((match = pattern.exec(html)) !== null) {
      if (match[1] && !igExclude.includes(match[1].toLowerCase())) {
        instagramUrl = 'https://instagram.com/' + match[1];
        break;
      }
    }
    if (instagramUrl) break;
  }
  if (!instagramUrl) gaps.push('sem_instagram');

  results.push({ json: {
    ...lead,
    tagsTech: tags,
    gapsDetected: gaps,
    fazTrafegoPago: tags.includes('tem_pixel') || tags.includes('tem_google_ads'),
    temAgendamento: tags.includes('tem_agendamento'),
    websiteScanned: true,
    instagramUrl: instagramUrl,
    instagramSeguidores: 0
  }});
}
return results;

